#!/usr/bin/env python3
"""frontier-table.py — read greedy-frontier.log (output of standing-wave-pca
runs at varying k) and print a markdown table of the deployment frontier.

Each ALL-BOUNDARIES SUMMARY line gets parsed into (k, top1, top5_has_bl,
cosine, KL). Output a sorted table + a quick "knee" diagnostic that flags
where top-5_has_baseline drops below 80%, 70%, 50%.
"""

import re
import sys

LINE_RE = re.compile(
    r'\[pca\] ALL-BOUNDARIES SUMMARY \((\d+) layers compressed\): '
    r'top1=(\d+)/(\d+)=(\d+)% '
    r'top5_has_bl=(\d+)/(\d+)=(\d+)% '
    r'cosine_avg=([\d\.]+) '
    r'KL_avg=([\d\.]+)'
)

def main():
    if len(sys.argv) < 2:
        print("usage: frontier-table.py greedy-frontier.log [more.log ...]", file=sys.stderr)
        sys.exit(1)
    rows = []
    seen = set()
    for path in sys.argv[1:]:
        with open(path) as f:
            for line in f:
                m = LINE_RE.search(line)
                if m:
                    k = int(m.group(1))
                    if k in seen:
                        continue
                    seen.add(k)
                    rows.append({
                        'k': k,
                        'top1_pct': int(m.group(4)),
                        'top5_has_bl_pct': int(m.group(7)),
                        'cosine': float(m.group(8)),
                        'kl': float(m.group(9)),
                        'bw_saved_pct': k / 23 * 50.0,  # cov=0.50, 23 boundaries total
                    })
    if not rows:
        print("no SUMMARY rows parsed", file=sys.stderr)
        sys.exit(1)

    rows.sort(key=lambda r: r['k'])
    print("| k | bw_saved | top-1 | top-5_has_bl | cosine | KL |")
    print("|---|----------|-------|--------------|--------|-----|")
    for r in rows:
        print(f"| {r['k']:>2} | {r['bw_saved_pct']:>6.1f}% | "
              f"{r['top1_pct']:>3}% | {r['top5_has_bl_pct']:>3}% | "
              f"{r['cosine']:.3f} | {r['kl']:.3f} |")

    # Knee diagnostics
    print()
    for thresh in (90, 80, 70, 50, 30):
        passing = [r for r in rows if r['top5_has_bl_pct'] >= thresh]
        if passing:
            best = max(passing, key=lambda r: r['k'])
            print(f"top5_has_bl ≥ {thresh}%: max k = {best['k']} "
                  f"(bw_saved={best['bw_saved_pct']:.1f}%, "
                  f"top1={best['top1_pct']}%, KL={best['kl']:.2f})")

if __name__ == '__main__':
    main()
